    ensures
        dp.spec_s() == s@,
        dp.spec_t() == t@,
        dp.spec_s_len() == s.spec_len(),
        dp.spec_t_len() == t.spec_len();

fn set_s(&mut self, s: ArraySeqMtEphS<char>)
    ensures
        self.spec_s() == s@,
        self.spec_t() == old(self).spec_t();

