    ensures
        self.spec_s() == old(self).spec_s(),
        self.spec_t() == t@;

fn med_bottom_up_parallel(&mut self) -> (distance: usize)
    requires old(self).spec_s_len() + old(self).spec_t_len() < usize::MAX,
    ensures
        distance as nat == old(self).spec_med(
            old(self).spec_s_len(),
            old(self).spec_t_len()
        ),
        self.spec_s() == old(self).spec_s(),
        self.spec_t() == old(self).spec_t();

