fn get_memoized(&self, i: usize, j: usize) -> (val: Option<usize>)
    ensures
        match val {
            Some(v) => self.spec_memo().contains_key((i, j))
                && v == self.spec_memo()[(i, j)],
            None => !self.spec_memo().contains_key((i, j)),
        };

